 450→const fetchRemoteImageBuffer = async (imageUrl) => {
 451→    const controller = new AbortController();
 452→    const timeout = setTimeout(() => controller.abort(), REMOTE_IMAGE_FETCH_TIMEOUT_MS);
 453→
 454→    try {
 455→        const response = await fetch(imageUrl, {
 456→            method: 'GET',
 457→            redirect: 'follow',
 458→            signal: controller.signal,
 459→            headers: {
 460→                Accept: 'image/*,*/*;q=0.8',
 461→                'Accept-Encoding': 'identity',
 462→                'User-Agent': SHARE_IMAGE_FETCH_USER_AGENT,
 463→            },
 464→        });
 465→
 466→        if (!response.ok) {
 467→            throw new Error(`upstream image status ${response.status}`);
 468→        }
 469→
 470→        const finalUrl = response.url || imageUrl;
 471→        if (!isSafeRemoteImageUrl(finalUrl)) {
 472→            throw new Error('upstream redirected to unsafe url');
 473→        }
 474→
 475→        const contentType = String(response.headers.get('content-type') || '').toLowerCase();
 476→        if (!contentType.startsWith('image/')) {
 477→            throw new Error(`upstream content-type ${contentType || 'unknown'} is not an image`);
 478→        }
 479→        if (contentType.includes('image/svg')) {
 480→            throw new Error('svg images are not used for share previews');
 481→        }
 482→
 483→        const headerContentLength = Number(response.headers.get('content-length'));
 484→        if (Number.isFinite(headerContentLength) && headerContentLength > REMOTE_IMAGE_MAX_BYTES) {
 485→            throw new Error(`upstream content-length exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
 486→        }
 487→
 488→        const arrayBuffer = await response.arrayBuffer();
 489→        const buffer = Buffer.from(arrayBuffer);
 490→
 491→        if (!buffer.length) {
 492→            throw new Error('upstream image is empty');
 493→        }
 494→        if (buffer.length > REMOTE_IMAGE_MAX_BYTES) {
 495→            throw new Error(`upstream image exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
 496→        }
 497→
 498→        return {
 499→            buffer,
 500→            contentType,
 501→            byteLength: buffer.length,
 502→            finalUrl,
 503→        };
 504→    } finally {
 505→        clearTimeout(timeout);
 506→    }
 507→};
