 707→                .png()
 708→                .toBuffer();
 709→        }
 710→
 711→        // ── Dark overlay for text readability ──
 712→        const overlaySvg = `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 713→            <rect width="100%" height="100%" fill="black" fill-opacity="0.55"/>
 714→        </svg>`;
 715→        const overlayBuffer = await sharp(Buffer.from(overlaySvg)).png().toBuffer();
 716→
 717→        // ── Circular avatar ──
 718→        let avatarComposite = null;
 719→        const avatarSize = 180;
 720→        const avatarUrl = user.image_url;
 721→        if (avatarUrl) {
 722→            const avatarEval = evaluateShareImageCandidate(avatarUrl);
 723→            if (avatarEval.ok && avatarEval.resolvedUrl) {
 724→                try {
 725→                    const remote = await fetchRemoteImageBuffer(avatarEval.resolvedUrl);
 726→                    const circleMask = Buffer.from(
 727→                        `<svg width="${avatarSize}" height="${avatarSize}">
 728→                            <circle cx="${avatarSize / 2}" cy="${avatarSize / 2}" r="${avatarSize / 2}" fill="white"/>
 729→                        </svg>`
 730→                    );
 731→                    const resizedAvatar = await sharp(remote.buffer, { limitInputPixels: 60_000_000 })
 732→                        .resize(avatarSize, avatarSize, { fit: 'cover' })
 733→                        .png()
 734→                        .toBuffer();
 735→                    const circularAvatar = await sharp(resizedAvatar)
 736→                        .composite([{ input: circleMask, blend: 'dest-in' }])
 737→                        .png()
 738→                        .toBuffer();
 739→                    avatarComposite = circularAvatar;
 740→                } catch { /* skip avatar */ }
 741→            }
 742→        }
 743→
 744→        // ── Compose all layers ──
 745→        const composites = [
 746→            { input: overlayBuffer, top: 0, left: 0 },
 747→        ];
 748→
 749→        if (avatarComposite) {
 750→            const avatarLeft = Math.round((DEFAULT_OG_IMAGE_WIDTH - avatarSize) / 2);
 751→            composites.push({ input: avatarComposite, top: 100, left: avatarLeft });
 752→        }
 753→
 754→        const finalImage = await sharp(baseLayer)
 755→            .composite(composites)
 756→            .jpeg({ quality: 82, mozjpeg: true })
 757→            .toBuffer();
 758→
 759→        res.set('Content-Type', 'image/jpeg');
 760→        res.set('Cache-Control', 'public, max-age=3600');
 761→        return res.send(finalImage);
 762→    } catch (err) {
 763→        console.error('profile share image route error:', err?.message || err);
 764→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
