I now have a thorough understanding of the entire codebase. Let me compile the complete design plan.

---

# Implementation Plan: Weekly Recap Cards and Daily Writing Prompts

## Table of Contents
1. [Database Schemas](#1-database-schemas)
2. [Backend Service + Controller Design](#2-backend-service--controller-design)
3. [Frontend Component Design](#3-frontend-component-design)
4. [Prompt Seeding and Rotation](#4-prompt-seeding-and-rotation)
5. [Recap Computation (Query Design)](#5-recap-computation)
6. [API Endpoints](#6-api-endpoints)
7. [File List](#7-file-list)

---

## 1. Database Schemas

### Feature 1: Weekly Recap

No new table is needed. The recap is computed on-demand from existing tables (`journals`, `likes`, `comments`, `bookmarks`, `journal_views`, `users`). With 10 users the queries are fast enough to run live. If you want caching later, you can add a `weekly_recaps` table, but it is not necessary now.

**SQL file: `server/sql/weekly_recap.sql`**

```sql
-- weekly_recap.sql
-- RPC function to compute weekly stats for a given user.
-- Returns: personal stats + group stats in a single call.
-- Week boundary: Monday 00:00 UTC to Sunday 23:59:59 UTC.

CREATE OR REPLACE FUNCTION public.get_weekly_recap(
    p_user_id UUID,
    p_week_start TIMESTAMPTZ DEFAULT NULL
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $fn$
DECLARE
    v_week_start  TIMESTAMPTZ;
    v_week_end    TIMESTAMPTZ;
    v_result      JSONB;

    -- Personal stats
    v_my_posts       INT;
    v_my_words       INT;
    v_my_reactions    BIGINT;
    v_my_views        BIGINT;
    v_my_best_post   JSONB;

    -- Group stats
    v_total_posts     INT;
    v_most_active_id  UUID;
    v_most_active_name TEXT;
    v_most_active_img  TEXT;
    v_most_active_count INT;
    v_most_reacted_post JSONB;
BEGIN
    -- Default to the most recent completed week (last Monday)
    IF p_week_start IS NULL THEN
        v_week_start := date_trunc('week', now() AT TIME ZONE 'UTC') AT TIME ZONE 'UTC';
        -- If it's Monday and recap hasn't been seen yet, show last week
        -- Actually: always show the week that JUST ended (previous Monday)
        -- unless we're past Monday, in which case show the current week in progress
        -- Simplification: use current week (Mon-Sun range containing "now")
    ELSE
        v_week_start := p_week_start;
    END IF;

    v_week_end := v_week_start + INTERVAL '7 days';

    -- ── Personal: posts written this week ──
    SELECT count(*)
    INTO v_my_posts
    FROM journals
    WHERE user_id = p_user_id
      AND created_at >= v_week_start
      AND created_at < v_week_end;

    -- ── Personal: total word estimate (from content JSON text length / 5) ──
    SELECT coalesce(sum(
        CASE
            WHEN content IS NOT NULL THEN
                greatest(1, length(content::text) / 30)
            WHEN canvas_doc IS NOT NULL THEN
                greatest(1, length(canvas_doc::text) / 30)
            ELSE 0
        END
    ), 0)
    INTO v_my_words
    FROM journals
    WHERE user_id = p_user_id
      AND created_at >= v_week_start
      AND created_at < v_week_end;

    -- ── Personal: reactions received (likes on my posts this week) ──
    SELECT coalesce(count(*), 0)
    INTO v_my_reactions
    FROM likes l
    JOIN journals j ON l.journal_id = j.id
    WHERE j.user_id = p_user_id
      AND l.created_at >= v_week_start
      AND l.created_at < v_week_end;

    -- ── Personal: views received ──
    SELECT coalesce(sum(j.views), 0)
    INTO v_my_views
    FROM journals j
    WHERE j.user_id = p_user_id
      AND j.created_at >= v_week_start
      AND j.created_at < v_week_end;

    -- ── Personal: my best post (most views+likes combined) ──
    SELECT jsonb_build_object(
        'id', j.id,
        'title', j.title,
        'views', coalesce(j.views, 0),
        'like_count', coalesce(lc.cnt, 0)
    )
    INTO v_my_best_post
    FROM journals j
    LEFT JOIN LATERAL (
        SELECT count(*) AS cnt FROM likes WHERE journal_id = j.id
    ) lc ON TRUE
    WHERE j.user_id = p_user_id
      AND j.created_at >= v_week_start
      AND j.created_at < v_week_end
    ORDER BY (coalesce(j.views, 0) + coalesce(lc.cnt, 0) * 3) DESC
    LIMIT 1;

    -- ── Group: total posts from everyone ──
    SELECT count(*)
    INTO v_total_posts
    FROM journals
    WHERE created_at >= v_week_start
      AND created_at < v_week_end
      AND privacy = 'public';

    -- ── Group: most active writer ──
    SELECT j.user_id, u.name, u.image_url, count(*) AS cnt
    INTO v_most_active_id, v_most_active_name, v_most_active_img, v_most_active_count
    FROM journals j
    JOIN users u ON u.id = j.user_id
    WHERE j.created_at >= v_week_start
      AND j.created_at < v_week_end
      AND j.privacy = 'public'
    GROUP BY j.user_id, u.name, u.image_url
    ORDER BY cnt DESC
    LIMIT 1;

    -- ── Group: most-reacted post ──
    SELECT jsonb_build_object(
        'id', j.id,
        'title', j.title,
        'user_name', u.name,
        'user_image_url', u.image_url,
        'like_count', coalesce(lc.cnt, 0)
    )
    INTO v_most_reacted_post
    FROM journals j
    JOIN users u ON u.id = j.user_id
    LEFT JOIN LATERAL (
        SELECT count(*) AS cnt FROM likes WHERE journal_id = j.id
    ) lc ON TRUE
    WHERE j.created_at >= v_week_start
      AND j.created_at < v_week_end
      AND j.privacy = 'public'
    ORDER BY coalesce(lc.cnt, 0) DESC
    LIMIT 1;

    -- ── Build result ──
    v_result := jsonb_build_object(
        'week_start', v_week_start,
        'week_end', v_week_end,
        'personal', jsonb_build_object(
            'posts_written', v_my_posts,
            'total_words', v_my_words,
            'reactions_received', v_my_reactions,
            'views_received', v_my_views,
            'best_post', v_my_best_post
        ),
        'group', jsonb_build_object(
            'total_posts', v_total_posts,
            'most_active_writer', jsonb_build_object(
                'user_id', v_most_active_id,
                'name', v_most_active_name,
                'image_url', v_most_active_img,
                'post_count', v_most_active_count
            ),
            'most_reacted_post', v_most_reacted_post
        )
    );

    RETURN v_result;
END;
$fn$;
```

The key design decision here is an RPC function rather than multiple queries. With 10 users this runs in milliseconds. The word count is an approximation (content JSON length / 30) since content is stored as Lexical JSON, not plain text -- good enough for a "Spotify Wrapped" vibe.

### Feature 2: Daily Writing Prompts

**SQL file: `server/sql/writing_prompts.sql`**

```sql
-- writing_prompts.sql
-- Tables and seed data for daily writing prompts feature.

-- ── Prompts table ──
CREATE TABLE IF NOT EXISTS public.writing_prompts (
    id          SERIAL PRIMARY KEY,
    prompt_text TEXT NOT NULL,
    category    TEXT DEFAULT 'general',
    created_at  TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Index for rotation lookup
CREATE INDEX IF NOT EXISTS idx_writing_prompts_id ON public.writing_prompts (id);

-- ── Add prompt_id FK to journals ──
-- Nullable: most posts won't be prompt responses.
ALTER TABLE public.journals
    ADD COLUMN IF NOT EXISTS prompt_id INTEGER REFERENCES public.writing_prompts(id)
        ON DELETE SET NULL;

-- Index for fetching responses to a prompt
CREATE INDEX IF NOT EXISTS idx_journals_prompt_id
    ON public.journals (prompt_id)
    WHERE prompt_id IS NOT NULL;
```

Using a `prompt_id` FK on `journals` is the correct approach rather than tagging by prompt text, because:
- It enables the "grouped responses" view efficiently
- It survives prompt text edits
- It is cheap (nullable integer column)

The `category` column on `writing_prompts` is for future filtering but is not actively used in Phase 1.

---

## 2. Backend Service + Controller Design

### Feature 1: Weekly Recap

**Service: `server/services/recapService.js`**

Following the exact pattern of `discoveryService.js` -- a service that calls a Supabase RPC and shapes the result.

```javascript
// recapService.js
import supabase from "./supabase.js";

export async function getWeeklyRecapService(userId) {
    // Compute the start of the current ISO week (Monday 00:00 UTC)
    const now = new Date();
    const day = now.getUTCDay(); // 0=Sun, 1=Mon, ...
    const diffToMonday = day === 0 ? -6 : 1 - day;
    const monday = new Date(Date.UTC(
        now.getUTCFullYear(),
        now.getUTCMonth(),
        now.getUTCDate() + diffToMonday,
        0, 0, 0, 0
    ));

    const { data, error } = await supabase.rpc('get_weekly_recap', {
        p_user_id: userId,
        p_week_start: monday.toISOString(),
    });

    if (error) {
        throw { status: 500, error: 'Failed to compute weekly recap: ' + error.message };
    }

    return data;
}
```

**Controller: `server/controller/recapController.js`**

Following the exact pattern of `discoveryController.js`:

```javascript
// recapController.js
import { getWeeklyRecapService } from "../services/recapService.js";

export const getWeeklyRecapController = async (req, res) => {
    const userId = req.userId;
    try {
        const result = await getWeeklyRecapService(userId);
        return res.status(200).json(result);
    } catch (error) {
        const s = error?.status || 500;
        return res.status(s).json({ error: error?.error || 'failed to fetch weekly recap' });
    }
};
```

### Feature 2: Daily Writing Prompts

**Service: `server/services/promptService.js`**

```javascript
// promptService.js
import supabase from "./supabase.js";

// Deterministic daily prompt: day-of-year modulo prompt count
function getDayOfYear() {
    const now = new Date();
    const start = new Date(Date.UTC(now.getUTCFullYear(), 0, 0));
    const diff = now.getTime() - start.getTime();
    return Math.floor(diff / (1000 * 60 * 60 * 24));
}

export async function getTodaysPromptService() {
    // Get total prompt count
    const { count, error: countError } = await supabase
        .from('writing_prompts')
        .select('id', { count: 'exact', head: true });

    if (countError || !count || count === 0) {
        return null; // No prompts seeded yet
    }

    const dayOfYear = getDayOfYear();
    const promptIndex = dayOfYear % count;

    // Fetch the prompt at that offset (ordered by id for determinism)
    const { data, error } = await supabase
        .from('writing_prompts')
        .select('id, prompt_text, category')
        .order('id', { ascending: true })
        .range(promptIndex, promptIndex);

    if (error || !data || data.length === 0) {
        return null;
    }

    return data[0];
}

export async function getPromptResponsesService(promptId, limit = 10, before = null) {
    let query = supabase
        .from('journals')
        .select(`
            id, user_id, title, content, post_type, canvas_doc,
            created_at, privacy, views,
            users(id, name, image_url, badge),
            like_count: likes(count),
            comment_count: comments(count)
        `)
        .eq('prompt_id', promptId)
        .eq('privacy', 'public')
        .order('created_at', { ascending: false })
        .limit(limit + 1);

    if (before) {
        query = query.lt('created_at', before);
    }

    const { data, error } = await query;

    if (error) {
        throw { status: 500, error: 'Failed to fetch prompt responses: ' + error.message };
    }

    const hasMore = data.length > limit;
    const sliced = hasMore ? data.slice(0, limit) : data;

    return { data: sliced, hasMore };
}

export async function getPromptByIdService(promptId) {
    const { data, error } = await supabase
        .from('writing_prompts')
        .select('id, prompt_text, category')
        .eq('id', promptId)
        .single();

    if (error || !data) {
        return null;
    }
    return data;
}
```

**Controller: `server/controller/promptController.js`**

```javascript
// promptController.js
import {
    getTodaysPromptService,
    getPromptResponsesService,
    getPromptByIdService
} from "../services/promptService.js";

export const getTodaysPromptController = async (req, res) => {
    try {
        const prompt = await getTodaysPromptService();
        if (!prompt) {
            return res.status(200).json({ prompt: null });
        }
        return res.status(200).json({ prompt });
    } catch (error) {
        return res.status(500).json({ error: 'failed to fetch today\'s prompt' });
    }
};

export const getPromptResponsesController = async (req, res) => {
    const { promptId } = req.params;
    const { limit = 10, before } = req.query;
    try {
        const result = await getPromptResponsesService(
            parseInt(promptId),
            Math.min(parseInt(limit) || 10, 20),
            before || null
        );
        return res.status(200).json(result);
    } catch (error) {
        const s = error?.status || 500;
        return res.status(s).json({ error: error?.error || 'failed to fetch prompt responses' });
    }
};

export const getPromptByIdController = async (req, res) => {
    const { promptId } = req.params;
    try {
        const prompt = await getPromptByIdService(parseInt(promptId));
        if (!prompt) {
            return res.status(404).json({ error: 'prompt not found' });
        }
        return res.status(200).json({ prompt });
    } catch (error) {
        return res.status(500).json({ error: 'failed to fetch prompt' });
    }
};
```

