## 3. Frontend Component Design

### Feature 1: Weekly Recap Card

**New files to create:**
- `client/src/components/WeeklyRecap/WeeklyRecapCard.jsx`
- `client/src/components/WeeklyRecap/WeeklyRecapCard.css`

**Files to modify:**
- `client/src/components/HomePage/postCards/PostCards.jsx` -- insert `<WeeklyRecapCard />` at the top of the feed, before `{journals.map(...)}`
- `client/API/Api.js` -- add `getWeeklyRecap()` function

**WeeklyRecapCard.jsx design:**

The component sits inside `PostCards.jsx`, rendered once at the top of the feed (between the nav row and the journals list). It only appears when:
1. User is authenticated (`session` exists)
2. It is the current week (always available, but most impactful on Monday)
3. User has not dismissed it for this week (checked via `localStorage` with key `recap_dismissed_${weekKey}`)

```jsx
// WeeklyRecapCard.jsx - Conceptual structure
import { useQuery } from "@tanstack/react-query";
import { motion, AnimatePresence } from "framer-motion";
import { useState } from "react";
import { getWeeklyRecap } from "../../../API/Api";
import { useAuth } from "../../Context/useAuth";
import './WeeklyRecapCard.css';

export default function WeeklyRecapCard() {
    const { session, user } = useAuth();
    const [expanded, setExpanded] = useState(false);
    const [dismissed, setDismissed] = useState(() => {
        // Check localStorage for this week's dismissal
        const weekKey = getWeekKey();
        return localStorage.getItem(`recap_dismissed_${weekKey}`) === 'true';
    });

    const { data, isLoading } = useQuery({
        queryKey: ['weeklyRecap'],
        queryFn: () => getWeeklyRecap(session?.access_token),
        enabled: !!session && !dismissed,
        staleTime: 10 * 60 * 1000, // 10 min
        retry: false,
    });

    if (dismissed || !session || isLoading || !data) return null;

    const { personal, group } = data;

    const handleDismiss = () => {
        localStorage.setItem(`recap_dismissed_${getWeekKey()}`, 'true');
        setDismissed(true);
    };

    return (
        <motion.div className="recap-card" ...>
            {/* Collapsed view: key stats, expand button */}
            {/* Expanded view: full breakdown with group stats */}
            {/* Dismiss button */}
        </motion.div>
    );
}

function getWeekKey() {
    const now = new Date();
    const day = now.getUTCDay();
    const diff = day === 0 ? -6 : 1 - day;
    const monday = new Date(now);
    monday.setUTCDate(now.getUTCDate() + diff);
    return monday.toISOString().slice(0, 10); // "2026-02-23"
}
```

**Visual design (CSS):**
- Subtle gradient background using `--accent-amber` and `--accent-sage` at low opacity
- Glass morphism border matching existing `--bg-glass` / `--bg-glass-border`
