**DailyPromptCard.jsx design:**

```jsx
// DailyPromptCard.jsx - Conceptual structure
import { useQuery } from "@tanstack/react-query";
import { motion } from "framer-motion";
import { getTodaysPrompt, getPromptResponses } from "../../../API/Api";
import { useAuth } from "../../Context/useAuth";
import PromptBadge from "./PromptBadge";
import './DailyPromptCard.css';

export default function DailyPromptCard({ onRespondToPrompt }) {
    const { session } = useAuth();

    const { data: promptData } = useQuery({
        queryKey: ['todaysPrompt'],
        queryFn: getTodaysPrompt,
        staleTime: 30 * 60 * 1000, // 30 min - prompt changes daily
    });

    const prompt = promptData?.prompt;
    if (!prompt) return null;

    const { data: responsesData } = useQuery({
        queryKey: ['promptResponses', prompt.id],
        queryFn: () => getPromptResponses(prompt.id, 3),
        enabled: !!prompt?.id,
        staleTime: 5 * 60 * 1000,
    });

    const handleWriteResponse = () => {
        // Opens the Editor with prompt context
        onRespondToPrompt({
            promptId: prompt.id,
            promptText: prompt.prompt_text,
        });
    };

    return (
        <motion.div className="prompt-card" ...>
            <div className="prompt-card-header">
                <PromptBadge />
                <span className="prompt-card-label">Today's Prompt</span>
            </div>
            <p className="prompt-card-text">{prompt.prompt_text}</p>
            {session && (
                <button className="prompt-card-write-btn" onClick={handleWriteResponse}>
                    Write your take
                </button>
            )}
            {responsesData?.data?.length > 0 && (
                <div className="prompt-responses-preview">
                    <span className="prompt-responses-count">
                        {responsesData.data.length} response{responsesData.data.length !== 1 ? 's' : ''}
                    </span>
                    {/* Mini preview of response avatars */}
                </div>
            )}
        </motion.div>
    );
}
```

