### Client API Functions (additions to `client/API/Api.js`)

```javascript
// Weekly Recap
export const getWeeklyRecap = async (token) => {
    const headers = {};
    if (token) headers['Authorization'] = `Bearer ${token}`;
    const response = await apiRequest(`${BASE_URL}/recap/weekly`, {
        method: 'GET',
        headers,
    });
    if (!response.ok) {
        const err = await response.json().catch(() => ({}));
        throw new Error(err?.error || 'failed to fetch weekly recap');
    }
    return response.json();
};

// Daily Prompts
export const getTodaysPrompt = async () => {
    const response = await apiRequest(`${BASE_URL}/prompt/today`, { method: 'GET' });
    if (!response.ok) throw new Error('failed to fetch today\'s prompt');
    return response.json();
};

export const getPromptResponses = async (promptId, limit = 10, before = null) => {
    let url = `${BASE_URL}/prompt/${promptId}/responses?limit=${limit}`;
    if (before) url += `&before=${before}`;
    const response = await apiRequest(url, { method: 'GET' });
    if (!response.ok) throw new Error('failed to fetch prompt responses');
    return response.json();
};

export const getPromptById = async (promptId) => {
    const response = await apiRequest(`${BASE_URL}/prompt/${promptId}`, { method: 'GET' });
    if (!response.ok) throw new Error('failed to fetch prompt');
    return response.json();
};
```

